const express = require('express');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const { createClient } = require('redis');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

const redis = createClient({
  url: process.env.REDIS_URL
});

redis.on('error', (err) => {
  console.error('Redis error:', err);
});

const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

const CODE_TTL_SECONDS = 600;
const MAX_ATTEMPTS = 5;
const LOCKOUT_TTL_SECONDS = 900;

function generateSecureCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

function normalizePhone(phone) {
  return String(phone || '').trim();
}

function codeKey(userId) {
  return `2fa:code:${userId}`;
}

function attemptsKey(userId) {
  return `2fa:attempts:${userId}`;
}

function lockKey(userId) {
  return `2fa:lock:${userId}`;
}

app.post('/2fa/send', async (req, res) => {
  try {
    const userId = String(req.body.userId || '').trim();
    const phone = normalizePhone(req.body.phone);

    if (!userId || !phone) {
      return res.status(400).json({ error: 'userId and phone are required' });
    }

    const locked = await redis.exists(lockKey(userId));
    if (locked) {
      return res.status(429).json({ error: 'Too many failed attempts. Try again later.' });
    }

    const code = generateSecureCode();

    await redis.set(codeKey(userId), code, {
      EX: CODE_TTL_SECONDS
    });

    await redis.del(attemptsKey(userId));

    await twilioClient.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_FROM_NUMBER,
      to: phone
    });

    res.json({ message: 'Verification code sent' });
  } catch (err) {
    console.error('Send 2FA error:', err);
    res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/2fa/verify', async (req, res) => {
  try {
    const userId = String(req.body.userId || '').trim();
    const submittedCode = String(req.body.code || '').trim();

    if (!userId || !submittedCode) {
      return res.status(400).json({ error: 'userId and code are required' });
    }

    const locked = await redis.exists(lockKey(userId));
    if (locked) {
      return res.status(429).json({ error: 'Too many failed attempts. Try again later.' });
    }

    const storedCode = await redis.get(codeKey(userId));

    if (!storedCode) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    if (submittedCode !== storedCode) {
      const attempts = await redis.incr(attemptsKey(userId));
      if (attempts === 1) {
        await redis.expire(attemptsKey(userId), CODE_TTL_SECONDS);
      }

      if (attempts >= MAX_ATTEMPTS) {
        await redis.set(lockKey(userId), '1', { EX: LOCKOUT_TTL_SECONDS });
        await redis.del(codeKey(userId));
        await redis.del(attemptsKey(userId));
        return res.status(429).json({ error: 'Too many failed attempts. Try again later.' });
      }

      return res.status(401).json({
        error: 'Invalid code',
        attemptsRemaining: MAX_ATTEMPTS - attempts
      });
    }

    await redis.del(codeKey(userId));
    await redis.del(attemptsKey(userId));
    await redis.del(lockKey(userId));

    res.json({
      message: '2FA verification successful',
      accessGranted: true
    });
  } catch (err) {
    console.error('Verify 2FA error:', err);
    res.status(500).json({ error: 'Failed to verify code' });
  }
});

